INSERT INTO knowledge_documents (id, source_path, title, kind, tags, content, summary, chunk_count, is_archive, metadata, created_at, updated_at) VALUES
(gen_random_uuid(), 'kb/international/241', '多语种服务体系设计', 'spec', '{多语种,服务,设计}', '多语种服务体系四层次：1）收银层——界面语言自动检测浏览器语言+支持手动切换，收银员至少有基础英文沟通能力，常用收银话术多语种卡片备查；2）导玩层——设备界面多语种（中/英/当地语），导玩员引导手势+图文化（减少语言依赖），安全警示多语种（优先图标+图画）；3）客服层——客服入口按钮语言选择，自动回复FAQ多语种（覆盖80%常见问题），人工客服支持电话+聊天+WhatsApp/LINE；4）会员层——会员权益/积分/活动推送语言用户选择，短信/邮件模板各语言版本（含节假日问候），会员协议各语言法律效力同等。设计原则：优先图文化>当地语言>英文>中文，简化文字量（手机端显示友好），避免文化禁忌语（如猪/狗/偶像崇拜在特定信仰市场）。系统支持：i18n框架（react-i18next/i18n of NestJS）+翻译管理平台（Lokalize/Crowdin）+专业翻译公司核审（非机器直译）。', '四层多语种服务体系+设计原则+系统支持方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/242', '多语种营销内容生产', 'spec', '{多语种,营销,内容}', '多语种营销内容生产流程：1）源头内容创作（中文）+英文翻译（中英双语模板化）+当地语翻译（本地native+专业翻译）+本地化改编（本地国情/节日/梗）。2）内容管理——CM系统多语种版本管理（Notion+AirTable管理矩阵，按国家/语言/渠道/版本号追踪），定期内容审计（每季度更新+每个市场内容适配性检查）。3）质量控制——翻译+润色+本地化三个工序分离，专业译员（翻译）+母语审校（润色+本地感）+目标市场运营（适配性确认），QA checklis t（品牌语调一致性/文化禁忌/货币单位/日期格式/法律声明）。4）效率——翻译记忆库T M（复用70-80%降低30%成本），机器翻译（DeepL/GPT-4）初翻+人工精修降本50%，内容组件化（像搭积木组合各市场所需内容）。5）工具链——Lokalize项目管理+W ebhook自动同步CMS+GIT版本控制+自动部署到各市场站点/APP。年度预算：语种数量×$10-30K/语种（含翻译+审校+工具+维护）。', '五步多语种营销内容生产流程+成本管控方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/243', '跨境直播电商开展方案', 'spec', '{多语种,直播,电商}', '跨境直播电商三步走：1）准备阶段（1-2月）——选择平台（东南亚TikTok Shop/Shopee Live，中东Noon Live/Amazon Live，欧美TikTok+Amazon Live），注册跨境店铺+准备直播设备（补光灯+声卡+高清摄像头+双语提词器），选品（引流品$0.99-5+主推品$5-20+利润品$20-50）。2）执行阶段（持续）——主播2-4名（中英双语+当地语），每天2-4场直播（各市场高峰时段），直播内容（开箱/盲盒/挑战赛/赠品派送），挂车销售+限时折扣+满减。3）优化阶段（每月）——数据分析（观看→点击→下单→核销→复购），A/B测试（时间段/主播/品过/话术），达人合作（佣金10-30%+免费体验）。KPI：直播场均观看≥5,000/转化率≥3%/核销率≥60%/GMV $1,000-5,000/场（成熟期）。跨境物流：备货海外仓（7-14天达）/直邮（14-21天）分价格带使用。跨境直播最大挑战：物流时效与退换货，建议优先选择已有海外仓的市场。', '三步启动跨境直播电商+选品/主播/物流方案+KPI', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/244', '多语种客服中心建设', 'spec', '{多语种,客服,中心}', '多语种客服中心建设方案：1）选址——区域客服中心（东南亚曼谷中英泰语/中东迪拜中英阿拉伯/欧洲阿姆斯特丹中英法德）。2）团队——每个中心8-15人（全职+弹性），每语种至少2人（互为备份），母语优先+中文/英文B2+，培训周期4周（产品知识+系统使用+话术+文化敏感度+危机处理）。3）技术——全渠道路由（电话/WhatsApp/LINE/邮件/社交平台统一工作台），CC系统（CRM集成+自动路由+IVR多语种+录音+质检），AI辅助（自动翻译+FAQ推荐+情感分析转告警）。4）流程——响应<30秒（话）/15min（社交平台/chat）、首次解决率≥70%、客户满意度≥4.5/5。升级：L1（常见问题+自动回复）解决率60%→L2（一线坐席）30%→L3（专家）8%→L4（紧急）2%。5）外包vs自建：前期（年咨询<10万条）外包，中期（10-50万）自建核心+外包溢出，成熟（50万+）全自建。外包成本$2-5/通话，自建$1-3/通话。', '多语种客服中心选址/团队/技术/流程+外包vs自建成本分析', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/245', '海外门店法律文件模板库', 'spec', '{多语种,法律,模板}', '海外门店常用法律文件模板库：1）租赁合同模板——关键条款（免租期/租期/续租权/维修责任/解约条款/装修改造许可/转租权/营业额抽成条款），需当地律师审查符合当地合同法。2）供应商合同模板——品名规格/交货期/验收标准/保修期/付款条件/违约责任/争议解决。3）劳动合同模板——个人合同（固定期限/试用期/保密/竞业限制）和集体合同（如果需要），最低工资+加班费+年假+病假按当地法定最低以上。4）会员协议/用户条款——会员权益/积分规则/存储值/退款政策/IP归属/法律责任限制/隐私声明。5）活动免责声明——设备使用须知/安全警告/保险/个人责任/照片授权。6）IP授权协议——授权范围/地域/期限/费用/质量标准/监督权/终止条件。文件管理：各市场主模板由总部法务制定，当地律师审查进行适配，版本控制+变更记录+跨市场对比。提示：模板不是最终版本—每个市场需要当地律师最终审阅盖章。', '六类海外常用法律文件模板+当地律师审查要求', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/246', '跨境电商与实体店联动策略', 'spec', '{多语种,电商,联动}', '线上线下联动OMO策略海外版：1）线上引流到店——Shopee/Lazada/TikTok Shop购买体验券（到店核销），Google Maps广告（到店搜索），本地自媒体推广（线下活动预告打卡引流）。2）店内体验线上分享——打卡装置设计（适合拍照分享至Instagram/TikTok），到店体验赠送积分+线上叠加优惠，用户UGC征集（选优秀的发官方账号+送礼品卡）。3）线上线下同品——直播所卖套餐到店可用，线上积分线下通用（跨渠道打通），店内只能兑换的线下限定礼品（创造不可替代感）。4）社交电商——用户到店后引导关注社媒（Line/TikTok/Instagram获优惠券），离店后线上推送（再次到店促），老客分享专属链接（朋友购买双方获利）。5）数据打通——会员ID跨渠道识别（手机号/邮箱），用户旅程跨渠道追踪（从点击→付款→到店→离店→复购）。预计OMO渠道用户LTV比纯线上或纯线下高40-60%。', 'OMO五维策略+线上引流/到店体验/数据打通，LTV提升40-60%', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/247', '多语种品牌资产管理', 'spec', '{多语种,品牌,资产}', '多语种品牌资产管理六维度：1）品牌名称——中文核心+英文品牌+当地语品牌（译或音译），全球统一Logo（字体占位方案预留多语种），Slogan全球化+当地化双版本。2）视觉资产——品牌色（主色+辅色各语言不同文化含义需调整，如白色在亚洲象征纯洁在部分中东是丧事）、字体（Fall back fonts多语种覆盖）、图标库（避免文化敏感手势/动物）。3）内容资产——营销素材（海报/视频/文案各语种统一管理）、品牌手册（多语种版本，当地适配规则明确）、社交模板（各平台尺寸+各语言文字长度限制适配）。4）音频资产——Brand Music（全球统一旋律+当地语版本Jingle）、语音提示（设备开机/游戏、前台机器人的各语言录音）。5）数字资产——域名策略（brand.com全球统一+brand.th/brand.my国别站）、官方APP多语种发布（App Store Connect分语言截图描述和ASO）、SEO关键词多语种矩阵。6）管理——DAM系统管理所有品牌资产，资产使用审批流程，品牌授权使用范围与标准，季度品牌审计（是否有跑偏/滥用的资产）。维护成本：年$20-50K（DAM+制作+审计）。', '六维度品牌资产管理+DAM系统+季度审计', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/248', '海外门店本地化招聘渠道', 'spec', '{多语种,招聘,渠道}', '海外门店招聘渠道矩阵：东南亚——印尼（Jobstreet+Karir.com+LinkedIn+WhatsApp群组+校园招聘）、泰国（JobsDB+LinkedIn+Facebook Group+大学就业中心+驻泰中资企业协会）、越南（VietnamWorks+TopCV+Facebook+LinkedIn+校园）。中东——阿联酋（LinkedIn主渠道+NaukriGulf+Indeed+Bayt+当地报纸/社区）+沙特（LinkedIn+Bayt+Wzuf等本地平台+人力外包公司）+猎头招聘管理层。日韩——日本（Recruit+Indeed+マイナビ+Doda+LinkedIn+留华学生群）、韩国（Saramin+Job Korea+LinkedIn+大学合作）。欧美——英国（Indeed+LinkedIn+Reed+Jobsite+猎头）、美国（Indeed+LinkedIn+Glassdoor+ZipRecruiter+Monster+当地社群）。成本——每个国家每个招聘岗位$50-500（平台费）+猎头费15-25%年薪（管理层）。招聘流程：筛选（1-2周）→初试（视频30min）→复试（业务负责人40min+笔/实践测试）→终试（区域/国家经理30min）→Offer（3-5个工作日）。', '各市场招聘渠道+成本+招聘流程SOP', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/249', '海外门店数据安全架构', 'spec', '{多语种,安全,架构}', '海外门店数据安全架构七层设计：1）网络层——分支机构防火墙+入侵检测IDS/IPS+VPN回总部（IPsec）+SD-WAN多分支管理+分段网络（收银/管理/监控隔开）。2）应用层——多租户隔离（各市场数据独立）+WAF（Web应用防火墙防SQL注入XSS）+API网关认证限流（REST+GraphQL统一认证）+输入/输出净化+HTTPS强制。3）数据层——会员PII加密存储（AES-256-GCM）+数据库分库（各市场独立数据库实例）+密钥管理（AWS KMS/Azure Key Vault / 硬件HSM）+定期备份（多区域副本）。4）身份与访问层——IAM（SSO+RBAC/ABAC）+MFA强制（管理后台）+最小权限原则+季度权限审计+离职自动冻结+SaaS管理按角色。5）日志审计层——全量操作审计日志（保留1年）+SIEM安全事件集中管理+异常行为自动告警（暴力破解/数据批量导出）+合规报告自动生成。6）终端层——门店POS设备锁+远程擦除+防病毒+补丁管理。7）物理层——数据中心/服务器机房门禁/监控/温湿度/IP防护。年度安全预算：IT预算的10-15%，含工具+人员+审计+保险+应急。', '七层数据安全架构+年度安全预算配比', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/250', '海外市场支付系统对接', 'spec', '{多语种,支付,系统}', '海外支付系统对接方案：1）聚合支付网关——Adyen（全球，200+支付方式，费率2.5-3.5%+$0.10/笔）、Stripe（欧美日韩，2.2-2.9%+$0.30）、PayPal（全球，2.99%+$0.49）、Airwallex（亚太强，1.5-2%+$0.20）。2）本地支付——东南亚（Truemoney泰国/GoPay印尼/GrabPay/Gcash菲律宾/Shopee Pay）、中东（STC Pay沙特/Careem Pay阿联酋/Tabby先买后付BNPL）、日韩（PayPay/Line Pay日本/Kakao Pay韩国）、欧美（Apple Pay+Google Pay+Klarna/Afterpay BNPL+ACH direct debit）。3）技术对接——API集成（REST+SDK+Webhook回调）+沙箱测试环境+ACID事务+幂等性保证（防重复）。4）结算与汇回——多币种结算账户（网关自动换汇）+T+1/3结算周期+月结平台手续费对账+自动汇回（预设汇率阈值和频次）。5）风控——Fraud规则引擎（IP属地+交易频次+金额异常+黑名单）+3DS校验+无卡交易CVV+CVC验证+Chargeback争议处置（团队或外包处理）。6）合规——PCI DSS认证（支付处理合规）+各国央行/监管要求（CBUAE阿联酋/BOT泰国/BI印尼）。部署优先级：先适配Top3支付方式（覆盖当地80%以上消费者）+再扩展长尾支付。', '全球支付网关对比+本地支付矩阵+技术/结算/风控/合规全方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/251', '多语种设备本地化适配流程', 'spec', '{多语种,设备,适配}', '设备多语种本地化适配流程：1）UI本地化——抽离所有UI字符串到资源文件（.json/po/xliff /），翻译+文化适配（OK手势的禁忌/emoji替换）+长度测试（德语长了30%/阿拉伯语RTL）。2）语音本地化——录制当地语言语音包（专业配音演员+播音室，UY录音+多版本）+音频测试（音量/音调/清晰度/背景噪适配）。3）支付适配——认证测试（如果目标市场认证要求已变更则需重新认证，如沙特SASO获更新）+支付SDK集成（当地收单行测试+Gateway沙箱联调）+支付失败兜底/离线模式。4）网络适配——运营商兼容性测试（SIM卡&移动网络/门店WiFi/双频段）+网络不稳定兜底策略（离线收银40小时可用+同步优先上传交易+后传设备日志）。5）内容与管理——多语言设备固件OTA下发（A/B分区更新+流量控制+断点续传+不更新也能用现场）+远程配置和升级FOTA。每台设备本地化成本：UI翻译$200-500/语言+语音录制$1,000-3,000/语言+认证测试$2,000-8,000/市场+集成开发$2,000-5,000/语言。优先适配语种：英语（必须）+阿拉伯语（中东）+泰语（东南亚核心）+印尼语+越南语+日语+韩语。', '五步设备本地化流程+成本估算+语种优先级', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/252', '海外市场食品安全管理', 'spec', '{多语种,食品,合规}', '海外门店涉及餐饮时的食品安全管理：1）许可证——食品经营许可证（各国审批：泰国FDA/印尼BPOM/阿联酋Municipality/DM+Food Safety Cert/日韩厚生劳动省）、HACCP认证（越来越多的市场强制要求，尤其做热食）。2）供应链——食材本地采购（避免进口成本+时效）+供应商资质（产地证明+保质期+运输温控）+每批到货检验。3）食品处理——分餐/生熟分开/温度控制（冷链<5°C/热藏>60°C）+交叉污染防护+单次制作不库存+操作人员持健康证+三层手套+口罩+发网。4）卫生检查——每日开业前准备环节自检表（冷藏温度+食材外观/害虫检查+设备清洁）+地方卫生当局定期检查（警告/罚款¥违规项目），等级公示（客户看得到）。5）过敏原——常见过敏原（花生/麸质/乳制品）标于菜单+服务人员被问及时给出准确信息。6）追溯与召回——食材按Lot#记录，可追溯至供应商批次，召回流程：发现+停止使用+通知供应商+报告卫生局+公告+配合下架。食品占营收比重目标5-10%（不建议占比过高，增加合规管理复杂度），但好的小食可提升到店时长和客单价。', '海外门店食品安全六大管理要点+食品占营收5-10%建议', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/253', '海外门店本地内容营销', 'spec', '{多语种,内容,营销}', '海外门店本地内容创作指南：1）内容类型——攻略型（第一次来XX怎么玩/选购币套餐指南）、互动型（你在XX抓到的最离谱的娃娃、XX挑战赛）、故事型（品牌故事/创始人故事/本地KOL探店）、促销型（限时活动/新设备上架/会员权益）。2）内容频率——每天至少1条Instagram Story+2条TikTok（短视频）+2条Facebook/本地社交平台+1篇博客/每周（攻略/科普深文）+1场直播/周。3）内容创作——本地团队产出60%+总部提供可本地化的模板30%+UGC 10%（客户到店打卡分享）。4）创意方向——融入当地文化梗（天气/食物/交通/节日常用的当地梗），本地语言金句（非翻译，是当地人会发那种口语化表达），本地知名地点/建筑/美食打卡。5）素材生产——手机拍摄（日常运营可做，客户真实感强）+专业拍摄（广告/活动预告/品牌大片）+UGC征集+与本地内容创者/MCN签约按月外包。6）本地化模板库——每月初发放可本地化的模板（海报文案5-8版+短视频脚本3-5个），各地运营选择+二次加工。内容团队配置：每市场1-2名内容运营，总部1名内容总监监管所有市场内容风格。', '六维本地内容营销策略+各市场内容团队配置', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/254', '海外市场促销活动运营', 'spec', '{多语种,促销,活动}', '海外市场促销活动类型与运营：东南亚——买币送币（买10送2/买20送5+会员积分翻倍）、限量周边满换、Holiday Bundle（泼水节/开斋节/圣诞3天欢乐套餐）、签到7天送大礼。中东——VIP专属晚间时段（22:00后俱乐部风体验）、女性专场（女性半价、赠饮品+护肤小样）、家庭套餐（成人+儿童捆绑）、高价值用户专属体验（定制奖品+管家式服务）。日韩——限定款周边+封测优先（日本）、学生折扣（韩国平日）、Pop-up限时主题店（日韩均吃香）、二次元主题月（coser巡场/痛机布置）。欧美——Season Pass（季度通票无限制玩）、Happy Hour（平日特定时段5折）、Birthday Party Package（过生日的套餐/包间+消费）、League Table（长期赛事循环+奖品累进）。活动ROI计算：净增营收÷活动总成本（含人员/物料/机会成本），ROI目标≥2.0。每月活动频率：小型活动8-12个（无额外成本/纯优化）、中型3-5个（成本$500-2K）、大型1-2个（成本$5-20K）。', '四大区域促销活动类型+ROI计算+活动频率标准', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/255', '多语种员工手册编制', 'spec', '{多语种,员工,手册}', '多语种员工手册标准化框架：1）公司介绍——品牌历史+使命愿景+全球分布图+组织架构+企业文化核心价值观+集团介绍。2）员工权益——薪资结构（当地法定最低+分级标准+计算方式+发放日期）+社保福利（各国各自规定）+假期（年假/病假/产假/婚丧假/公共假日）+奖金/调薪机制+申诉渠道。3）行为准则——仪容仪表标准（分市场不同，中东女性头巾optional/东南亚较随意/日韩严厉） +考勤规则（打卡/迟到/早退/旷工）+禁止事项（内线/竞业/受贿/泄密）+处分制度（口头警告/书面/PIP/解雇按阶梯）-每个国家的劳动法不同，尤其解雇的法定标准差异大。4）工作安全——消防安全+设备安全+人身安全+急救指引+安全责任人+报告制度。5）分支特定政策——本地化假期+交通津贴/补贴+餐补+通讯补贴+加班规定。版本管理：总部提供中/英文主版本，各市场HR完成本地化适配（与当地劳动法核验一致），电子版员工手册全员签收，纸质版备查。各市场至少每年度更新手册（法规变化）。', '多语种员工手册五大框架+版本管理+年度更新', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/256', '电玩城跨界融合新业态', 'spec', '{跨界,融合,业态}', '电玩城与其他业态跨界融合的五大方向：1）电竞+X——电竞馆+直播+周边零售+训练基地+赛事组织+电竞青训，营收结构（游戏区40%+餐饮25%+零售15%+赛事/培训20%）。2）亲子FEC——淘气堡+软游乐+电玩+餐饮+派对房+早教课程，工作日可做幼儿园/学校秋游/亲子早教课，坪效高于纯电玩的1.5倍。3）娱乐综合体——游乐+影院+餐饮+零售+KTV+密室+剧本杀的组合，适合3000㎡+，共享客流（一个用户过来可以呆半天），客单价提升50-100%。4）IP主题店——某个IP场景（动漫/游戏/国潮）的沉浸式门店，门票¥39-79+园内二消，复购率较高（IP的粉丝型消费），参考上海animate cafe和日本Pikachu Sweets。5）社交夜店风——夜晚切换到酒吧/Club模式（灯光+S音乐+酒水21:00后），白天做青少年生意晚上做大人生意，需持酒牌+解决未成年人进入管控。融合模式关键成功要素：运营复杂度上升（多重业态同时经营），需要更专业的各业务线团队与复合型店长，坪效核算需分业态拆分+跨业态的业务协同和人员复用。', '五大跨界融合方向+不同模式的营收结构和运营要点', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/257', '文旅融合与主题公园联动', 'spec', '{跨界,文旅,主题公园}', '电玩城与文旅产业融合六大机会：1）景区店——在热门景区出入口/商业街开设（年客流千万级景区如泰国大皇宫周、杭州西湖），游客转化率5-15%的充值币消费。2）主题公园合作——在大型主题公园（迪士尼/环球影城/长隆）内或相邻商业体开设，共享客流+提供不同的娱乐体验（从过山车到游戏币）。合约模式：固定租金+营收分成（8-15%给主题公园）。3）夜间经济——在夜市/酒吧街/城市夜间活动区域设店，需要夜间延时经营牌照（部分国家需要特别许可）。4）度假村/酒店内设——为滨海/山野度假村旅客打造傍晚至深夜娱乐场景，与酒店房晚销售捆绑（住客获赠游戏币/套餐）。5）IP植入——与文旅项目IP合作（动物/神话/自然等），联名场景设计+限定礼品+专属设备改造，避免抄袭烂大街所以需要专有IP授权。6）研学游——与学校/教育机构合作，以设备原理体验（物理/机械互动演示）符合STEAM教育的门店活动，工作日下午或周末开放团队预约。文旅渠道合作优势：一次性获客批量（团单/团队集合），营销成本极低（渠道自带流量已经来旅游了），旺季溢出效应（黄金周/假期客流倍增，门店收益弹性较大）。', '六项文旅融合机会+景区店/IP植入/研学游等合作模式', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/258', '电玩城+餐饮融合方案', 'spec', '{跨界,餐饮,融合}', '电玩城+餐饮融合三大模式：1）轻餐吧——吧台+简单冷食（饮品/冰淇淋/爆米花/热狗/薯条），15-30㎡吧台+6-8张吧椅，营收占比10-15%，毛利率60-70%。设备（水吧一体机/制冰机/微波炉/炸炉）+许可证（饮品+简单加热）。适合面积紧凑（400-800㎡）的门店。2）主题餐厅——独立用餐区（80-120㎡，40-60座位）+自选热食（中式快餐/西式扒饭/面食简餐）+自助饮品，营收占比20-30%，毛利率55-65%。需完整餐饮团队（厨师长+前厅经理+服务员）+厨房设备投入¥15-30万+注册餐饮公司。适合大店（≥800㎡）。3）社交轻酒吧——晚上21:00切换为酒吧模式（灯光+音乐+酒水+小吃），营收占比30-50%（夜晚时段的时段特性），毛利率65-75%。需要酒牌（各地办理时间不同，香港6-12月，泰国易，中东穆斯林国家基本办不了或代价高）+晚间时段人员运营编制调整（晚上以调酒+侍应+安保为主）。融合关键：动线分区（餐饮区与游戏区互不干扰气味烟味）、空气净化（油烟处理系统+新风量按餐饮标准）、账务系统统一（会员积分可跨品类用+销售分品类核算）、营业时间餐饮可先于游戏营业（卖早餐/早茶+午餐+下午茶：一块场地多板块时间复用）。', '三种电玩+餐饮融合模式+分区/空气/账务/时间管理要点', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/259', '电玩城密室逃脱跨界', 'spec', '{跨界,密室,融合}', '电玩城引入密室逃脱/剧本杀的可行性方案：1）植入模式——利用已有的闲置/暗角的区域或地下室改造1-2个密室主题（60-120㎡/主题），投资¥15-30万/主题（道具+机关+装饰+音响+灯光），售价¥68-198/人/60min，毛利率70-80%。收益模型：日均4-6场/主题，月营收¥3-8万/主题。2）联动模式——电玩币通兑密室+密室通关赠送游戏币，交叉导流。密室用户到电玩区转化率约15-25%，电玩用户转密室约5-10%，主要是双方共享场地和客流，高峰期为周末+节假日。3）一店两制——独立密室区（非通票、需单独预约+购票）+单独密室团队（店中店，有独立接待/场控/DM/主持人）。密室/IP/谜题每月更新（1/3内容替换）+季度大更新。4）投资回收——单个密室主题6-12个月回本，密室带动整体门店客流提升10-20%（因为密室用户群体与电玩群体有重叠但年龄略大+男比略高+通常结伴2-6人，填补工作日晚间时段作用明显）。5）运营难点——密室人员招聘难（好的DM/主持人稀缺，各地薪资¥5-10K/月），成本较高+经常更新主题的持续投入+安全要求高（密室密闭空间须有多重逃生机制，消防审批严格）。政策面：各地消防对密室的审批政策不同（有些城市已收紧密室审批），建议提前与当地消防/文旅部门沟通。', '密室/剧本杀植入电玩城的模式/收益/投资回收/运营难点分析', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/260', '电玩城与社交娱乐融合', 'spec', '{跨界,社交,娱乐}', '电玩城向社交空间转型方案：1）社交区设计——开放式的休息交流区（沙发+茶几+充电插座+免费WiFi+桌游桌，桌游(阿瓦隆/狼人杀/UNO/三国杀）免费出借）+打卡装置（霓虹灯墙/泡泡池/无限镜等设计，适合拍照晒图）=有效拉长停留时间30-60min+平均客单价提升8-15%。2）社群运营——门店私域社群（Line群/微信群/WhatsApp群)，按兴趣分组（赛车群/拳皇群/抓娃娃群/竞赛群各一个）+每周主题之夜+群内专属福利+会员生日专属社群祝福+新设备/活动群内提前内测预订。社群活跃度目标：日活跃≥200人的一个总群+兴趣分群。3）电竞赛事与社交——每周小赛+月度城市赛+年度区域赛，不参赛的也可观赛和押注（虚拟积分预测赢家），营造观赛社交氛围+赛事直播+投屏+奖品+解说。4）活动型社交——缘分扭蛋（"我不认识你但我帮你抓娃娃"等配对破冰社交活动）+会员生日当月专属派对包场+月度匿名信(写给下次来的一个人)等轻社交创意活动。5）跨业态社交合作——与隔壁奶茶/咖啡厅做联名（持消费小票互惠通行证，进店即得对方¥5代金券）+合作桌游俱乐部/脱口秀剧场，互相引流。目标：让客户"不是为了玩游戏而来，而是为了来这个社交空间顺便玩玩"。', '电玩城社交化转型五要素+社群运营+活动设计', 3, false, '{}'::jsonb, NOW(), NOW());
